B.a6G=new A.a3(B.a7n,["Kh\xe1m ph\xe1 Trung Qu\u1ed1c: B\u1eafc Kinh - Th\u01b0\u1ee3ng H\u1ea3i - Tr\u01b0\u01a1ng Gia Gi\u1edbi","Trung Qu\u1ed1c l\xe0 m\u1ed9t \u0111\u1ea5t n\u01b0\u1edbc c\xf3 b\u1ec1 d\xe0y l\u1ecbch s\u1eed v\xe0 v\u0103n h\xf3a \u0111\u1ed3 s\u1ed9. H\xe3y c\xf9ng kh\xe1m ph\xe1 nh\u1eefng \u0111\u1ecba danh bi\u1ec3u t\u01b0\u1ee3ng nh\u1ea5t.","Ng\xe0y 1: Tham quan V\u1ea1n L\xfd Tr\u01b0\u1eddng Th\xe0nh & Th\u1eadp Tam L\u0103ng \xb7 Ng\xe0y 2: Kh\xe1m ph\xe1 T\u1eed C\u1ea5m Th\xe0nh, Qu\u1ea3ng Tr\u01b0\u1eddng Thi\xean An M\xf4n & Di H\xf2a Vi\xean (Cung \u0110i\u1ec7n M\xf9a H\xe8) \xb7 Ng\xe0y 3: Tr\u1ea3i nghi\u1ec7m Ph\u1ed1 C\u1ed5 Th\u01b0\u1ee3ng H\u1ea3i v\xe0 mua s\u1eafm t\u1ea1i Nam Kinh L\u1ed9.","H\u01b0\u1edbng d\u1eabn: B\u1ea1n n\xean \u0111\u1ed5i ti\u1ec1n sang Nh\xe2n d\xe2n t\u1ec7 tr\u01b0\u1edbc v\xe0 c\xe0i \u0111\u1eb7t c\xe1c \u1ee9ng d\u1ee5ng thanh to\xe1n nh\u01b0 Alipay ho\u1eb7c WeChat Pay. \u0110\u1ec3 tham quan T\u1eed C\u1ea5m Th\xe0nh, b\u1ea1n c\u1ea7n \u0111\u1eb7t v\xe9 tr\u01b0\u1edbc \xedt nh\u1ea5t 7 ng\xe0y qua \u1ee9ng d\u1ee5ng ch\xednh th\u1ee9c.","T\u1eed C\u1ea5m Th\xe0nh, V\u1ea1n L\xfd Tr\u01b0\u1eddng Th\xe0nh, Cung \u0110i\u1ec7n M\xf9a H\xe8 (Di H\xf2a Vi\xean), S\xe2n v\u1eadn \u0111\u1ed9ng T\u1ed5 Chim, Thi\xean \u0110\xe0n."],t.w)
